import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import '../App.css';

function MetaAds() {
  const { user, makeRequest } = useAuth();
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [activeTab, setActiveTab] = useState('dashboard'); // Mudando para dashboard como padrão
  const [filtroRegiao, setFiltroRegiao] = useState('');
  const [filtroEstado, setFiltroEstado] = useState('');
  const [filtroStatus, setFiltroStatus] = useState('');
  const [campaigns, setCampaigns] = useState([]);
  const [selectedCampaign, setSelectedCampaign] = useState('');
  const [dateRange, setDateRange] = useState('last_30d');
  const [statusFilter, setStatusFilter] = useState('ACTIVE'); // Novo filtro de status
  const [apiStatus, setApiStatus] = useState(null);
  const [tokenStatus, setTokenStatus] = useState(null);
  const [realTimeData, setRealTimeData] = useState([]); // Dados em tempo real
  const [lastUpdate, setLastUpdate] = useState(null);
  const [autoRefresh, setAutoRefresh] = useState(false);
  const [pricing, setPricing] = useState([]);
  const [leads, setLeads] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editingPricing, setEditingPricing] = useState(null);
  const [syncing, setSyncing] = useState(false);
  const [formData, setFormData] = useState({
    city: '',
    state: '',
    country: 'BR',
    cost_per_lead: '',
    spend: '',
    leads: '',
    date_range: 'manual'
  });

  // Verificar se usuário é admin
  const isAdmin = user?.tipo === 'admin';

  useEffect(() => {
    if (activeTab === 'pricing') {
      fetchPricing();
      fetchCampaigns();
    } else {
      fetchLeads();
    }
  }, [activeTab]);

  useEffect(() => {
    testApiConnection();
  }, []);

  const fetchPricing = async () => {
    try {
      const params = new URLSearchParams();
      if (filtroRegiao) params.append('cidade', filtroRegiao);
      if (filtroEstado) params.append('estado', filtroEstado);
      if (filtroStatus) params.append('status', filtroStatus);

      const response = await makeRequest(`/meta-ads/pricing?${params}`);
      const data = await response.json();

      if (response.ok) {
        setPricing(data);
      } else {
        console.error('Erro ao carregar preços:', data.error);
        setMessage('Erro ao carregar preços: ' + data.error);
      }
    } catch (error) {
      console.error('Erro ao carregar preços:', error);
      setMessage('Erro ao conectar com o servidor');
    } finally {
      setLoading(false);
    }
  };

  const fetchLeads = async () => {
    try {
      const response = await makeRequest('/meta-ads/leads');
      const data = await response.json();

      if (response.ok) {
        setLeads(data);
      } else {
        console.error('Erro ao carregar leads:', data.error);
        setMessage('Erro ao carregar leads: ' + data.error);
      }
    } catch (error) {
      console.error('Erro ao carregar leads:', error);
      setMessage('Erro ao conectar com o servidor');
    } finally {
      setLoading(false);
    }
  };

  const fetchCampaigns = async () => {
    try {
      const response = await makeRequest('/meta-ads/campaigns');
      const data = await response.json();

      if (response.ok) {
        setCampaigns(data.data || []);
      } else {
        console.error('Erro ao carregar campanhas:', data.error);
        setMessage('Erro ao carregar campanhas: ' + (data.error || 'Erro desconhecido'));
      }
    } catch (error) {
      console.error('Erro ao carregar campanhas:', error);
      setMessage('Erro ao conectar com o servidor');
    }
  };

  const testApiConnection = async () => {
    try {
      const response = await makeRequest('/meta-ads/test-connection');
      const data = await response.json();
      setApiStatus(data);
      setTokenStatus(data.tokenStatus);
    } catch (error) {
      setApiStatus({ 
        success: false, 
        message: 'Erro ao testar conexão',
        error: error.message || 'Erro desconhecido'
      });
    }
  };

  const checkTokenStatus = async () => {
    try {
      const response = await makeRequest('/meta-ads/token-status');
      const data = await response.json();
      setTokenStatus(data);
    } catch (error) {
      console.error('Erro ao verificar status do token:', error);
    }
  };

  const extendToken = async () => {
    try {
      setLoading(true);
      const response = await makeRequest('/meta-ads/extend-token', {
        method: 'POST'
      });
      const data = await response.json();

      if (response.ok) {
        setMessage(`✅ ${data.message}\n\n🔑 Novo token: ${data.newToken}\n\n⚠️ Copie e atualize seu .env!`);
        checkTokenStatus();
      } else {
        setMessage('❌ Erro ao renovar token: ' + (data.error || 'Erro desconhecido'));
      }
    } catch (error) {
      setMessage('❌ Erro ao renovar token: ' + (error.message || 'Erro desconhecido'));
    } finally {
      setLoading(false);
    }
  };

  const syncCampaigns = async () => {
    try {
      setSyncing(true);
      setMessage(''); // Limpar mensagens anteriores
      const response = await makeRequest('/meta-ads/sync-campaigns', {
        method: 'POST'
      });
      const data = await response.json();

      if (response.ok) {
        setMessage(data.message);
        fetchPricing();
        setTimeout(() => setMessage(''), 5000);
      } else {
        setMessage('Erro ao sincronizar: ' + (data.error || 'Erro desconhecido'));
      }
    } catch (error) {
      setMessage('Erro ao sincronizar campanhas: ' + (error.message || 'Erro desconhecido'));
    } finally {
      setSyncing(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let response;
      if (editingPricing) {
        response = await makeRequest(`/meta-ads/pricing/${editingPricing.id}`, {
          method: 'PUT',
          body: JSON.stringify(formData)
        });
      } else {
        response = await makeRequest('/meta-ads/pricing', {
          method: 'POST',
          body: JSON.stringify(formData)
        });
      }

      const data = await response.json();

      if (response.ok) {
        setMessage(editingPricing ? 'Preço atualizado com sucesso!' : 'Preço cadastrado com sucesso!');
        setShowModal(false);
        setEditingPricing(null);
        setFormData({
          cidade: '',
          estado: '',
          preco_por_lead: '',
          campanha_id: '',
          campanha_nome: '',
          periodo_inicio: '',
          periodo_fim: '',
          observacoes: '',
          status: 'ativo'
        });
        fetchPricing();
        setTimeout(() => setMessage(''), 3000);
      } else {
        setMessage('Erro ao salvar preço: ' + data.error);
      }
    } catch (error) {
      console.error('Erro ao salvar preço:', error);
      setMessage('Erro ao salvar preço');
    }
  };

  const handleEdit = (pricing) => {
    setEditingPricing(pricing);
    setFormData({
      city: pricing.city || pricing.region?.split(' - ')[0] || '',
      state: pricing.state || pricing.region?.split(' - ')[1] || '',
      country: pricing.country || 'BR',
      cost_per_lead: pricing.cost_per_lead || '',
      spend: pricing.spend || '',
      leads: pricing.leads || '',
      date_range: pricing.date_range || 'manual'
    });
    setShowModal(true);
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const formatarPreco = (preco) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL'
    }).format(preco);
  };

  const formatarData = (data) => {
    return new Date(data).toLocaleDateString('pt-BR');
  };

  const estados = [
    'AC', 'AL', 'AP', 'AM', 'BA', 'CE', 'DF', 'ES', 'GO', 'MA',
    'MT', 'MS', 'MG', 'PA', 'PB', 'PR', 'PE', 'PI', 'RJ', 'RN',
    'RS', 'RO', 'RR', 'SC', 'SP', 'SE', 'TO'
  ];

  // Novo método para buscar dados em tempo real
  const fetchRealTimeData = async () => {
    try {
      setLoading(true);

      const response = await makeRequest(`/meta-ads/real-time-insights?dateRange=${dateRange}&status=${statusFilter}`);
      const data = await response.json();

      if (response.ok) {
        setRealTimeData(data);
        setLastUpdate(new Date());
        setMessage('Dados atualizados com sucesso!');
      } else {
        console.error('Erro ao carregar dados em tempo real:', data.error);
        setMessage('Erro ao carregar dados em tempo real');
      }
    } catch (error) {
      console.error('Erro ao buscar dados em tempo real:', error);
      setMessage('Erro ao buscar dados em tempo real');
    } finally {
      setLoading(false);
    }
  };

  // Auto refresh a cada 5 minutos
  useEffect(() => {
    let interval;
    if (autoRefresh && activeTab === 'dashboard') {
      interval = setInterval(fetchRealTimeData, 5 * 60 * 1000); // 5 minutos
    }
    return () => clearInterval(interval);
  }, [autoRefresh, activeTab, dateRange, statusFilter]);

  // Carregar dados ao mudar período ou status
  useEffect(() => {
    if (activeTab === 'dashboard') {
      fetchRealTimeData();
    }
  }, [dateRange, statusFilter, activeTab]);

  const formatarMoeda = (valor) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL'
    }).format(valor || 0);
  };

  const formatarNumero = (numero) => {
    return new Intl.NumberFormat('pt-BR').format(numero || 0);
  };

  const formatarDataHora = (data) => {
    return new Date(data).toLocaleString('pt-BR');
  };

  const getDateRangeLabel = () => {
    switch(dateRange) {
      case 'today': return 'Hoje';
      case 'last_7d': return 'Últimos 7 dias';
      case 'last_30d': return 'Últimos 30 dias';
      default: return 'Últimos 30 dias';
    }
  };

  const getStatusLabel = () => {
    switch(statusFilter) {
      case 'ACTIVE': return 'Apenas Ativas';
      case 'PAUSED': return 'Apenas Pausadas';
      case 'ALL': return 'Todas';
      default: return 'Apenas Ativas';
    }
  };

  if (!isAdmin) {
    return (
      <div className="container">
        <div className="alert alert-warning">
          <h3>🔒 Acesso Restrito</h3>
          <p>Apenas administradores podem acessar as configurações do Meta Ads.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="header">
        <h1>📊 Meta Ads Dashboard</h1>
        <p>Gerencie campanhas e analise performance em tempo real</p>
      </div>

      {message && (
        <div className={`alert ${message.includes('Erro') ? 'alert-error' : 'alert-success'}`}>
          {message}
        </div>
      )}

      {/* Tabs Navigation */}
      <div className="tabs">
        <button 
          className={`tab ${activeTab === 'dashboard' ? 'active' : ''}`}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
        <button 
          className={`tab ${activeTab === 'pricing' ? 'active' : ''}`}
          onClick={() => setActiveTab('pricing')}
        >
          💰 Preços por Cidade
        </button>
        <button 
          className={`tab ${activeTab === 'leads' ? 'active' : ''}`}
          onClick={() => setActiveTab('leads')}
        >
          👥 Leads
        </button>
        <button 
          className={`tab ${activeTab === 'api' ? 'active' : ''}`}
          onClick={() => setActiveTab('api')}
        >
          🔗 Integração API
        </button>
      </div>

      {/* Dashboard Tab */}
      {activeTab === 'dashboard' && (
        <div className="dashboard-container">
          {/* Controls */}
          <div className="dashboard-controls">
            <div className="filters-group">
              <div className="period-selector">
                <label>📅 Período:</label>
                <select 
                  value={dateRange} 
                  onChange={(e) => setDateRange(e.target.value)}
                  className="form-select"
                >
                  <option value="today">Hoje</option>
                  <option value="last_7d">Últimos 7 dias</option>
                  <option value="last_30d">Últimos 30 dias</option>
                </select>
              </div>

              <div className="status-selector">
                <label>🎯 Status:</label>
                <select 
                  value={statusFilter} 
                  onChange={(e) => setStatusFilter(e.target.value)}
                  className="form-select"
                >
                  <option value="ACTIVE">🟢 Apenas Ativas</option>
                  <option value="PAUSED">🟡 Apenas Pausadas</option>
                  <option value="ALL">🔘 Todas</option>
                </select>
              </div>
            </div>

            <div className="refresh-controls">
              <button 
                className="btn btn-primary"
                onClick={fetchRealTimeData}
                disabled={loading}
              >
